sql:
SELECT a.name, a.country AS country_code, c.country_name
FROM athletes AS a
JOIN countries AS c ON a.country = c.country_code;

SELECT a.team, a.date_of_birth
FROM athletes a
WHERE a.date_of_birth = (
    SELECT MIN(date_of_birth)
    FROM athletes
);

SELECT athletes.name, countries.country_name
FROM athletes
INNER JOIN countries ON athletes.country = countries.country_code;
